<template>
	<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
		:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
		@open="open">
		<view class="popup-title">{{title}}</view>
		<view class="block-height"></view>
		<view class="popup-content">
			<scroll-view @touchmove.stop :scroll-y="true" class="scroll_search_content" :rebound="false"
				:style="{height:cScrollHeight+'px'}" @scrolltolower="lower">
				<slot />
			</scroll-view>
		</view>
	</u-popup>
</template>

<script>
	import {
		mapMutations,
	} from 'vuex'

	export default {
		components: {

		},
		props: {
			show: {
				type: Boolean,
				default: false
			},
			customStyle: {
				type: Object,
				default: () => {}
			},
			title: {
				type: String,
				default: ''
			},
			// 滚动高度，单位rpx
			scrollHeight: {
				type: Number,
				default: 600
			},
		},
		data() {
			return {
				popupShow: false,
			}
		},
		computed: {
			cScrollHeight() {
				return uni.upx2px(this.scrollHeight)
			}
		},
		watch: {
			show: {
				handler(nv) {
					this.popupShow = nv
				},
				immediate: true
			}
		},
		mounted() {

		},
		methods: {
			open() {},
			close() {
				this.$emit('update:show', false)
			},
			lower() {},
		},
	}
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.block-height {
		height: 20rpx;
		background-color: #f4f4f5;
	}

	.popup-content {
		min-height: 600rpx;
	}
</style>