<template>
	<view @touchmove.stop.prevent>
		<view style="padding: 30rpx;">
			<u-form :model="form" label-position="top">
				<u-form-item label="状态">
					<u-input :value="statusText" type="select" @click="showStatus = true" />
					<u-action-sheet :list="statusList" v-model="showStatus"
						@click="handelStatusChange"></u-action-sheet>
				</u-form-item>
				<u-form-item label="创建时间">
					<uni-datetime-picker v-model="form.create_time" type="datetimerange" />
				</u-form-item>
			</u-form>
		</view>
		<view class="btn-box">
			<u-button @click="reset">重 置</u-button>
			<u-button type="primary" @click="submit">确 定</u-button>
		</view>
	</view>
</template>

<script>
	import ButtonCheckbox from '@/components/manage-search/button-checkbox'

	export default {
		components: {
			ButtonCheckbox
		},
		props: {
			formData: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				form: {
					status: '',
					create_time: '',
				},
				statusList: [{
						text: '待审核',
						value: 0
					},
					{
						text: '已通过',
						value: 1
					},
					{
						text: '审核失败',
						value: 2
					}
				],
				showStatus: false,
			}
		},
		computed: {
			statusText: {
				get() {
					if (this.form.status !== '') {
						let find = this.statusList.find(item => item.value == this.form.status)
						return find.text
					} else {
						return ''
					}
				}
			},
		},
		watch: {
			formData: {
				handler(nv) {
					this.form = nv
				},
				immediate: true
			}
		},
		methods: {
			handelStatusChange(e) {
				if (this.statusList[e].value !== '')
					this.form.status = this.statusList[e].value
				else
					this.form.status = ''
			},
			reset() {
				this.form = this.$options.data().form
			},
			submit() {
				this.$emit('filter', {
					...this.form
				})
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.btn-box {
		border-top: 1px solid #c8c9cc;
		display: flex;
		padding: 40rpx;
		gap: 20rpx;

		::v-deep {
			.u-btn {
				flex: 1;
			}
		}
	}
</style>