<template>
	<view class="page">
		<u-navbar title="充值审核" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="filter-btn" @click="showFilter =true"><text class="iconfont icon-guolv"></text>筛选</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false" @scrolltolower="lower">
			<view class="list-box">
				<view class="list-wrap">
					<view class="list-item" v-for="item,index in list" :key="index">
						<view class="acea-row row-between column-middle border-bottom pb-10">
							{{item.trade_sn}}
							<view>耗时：{{item.consume_time}}</view>
						</view>
						<view class="acea-row row-between-wrapper mt-20">
							<view class="acea-column column-middle gap-10 flex-1 overflow-hidden">
								<view>到账金额</view>
								<view>{{item.price}}</view>
							</view>
							<view class="acea-column column-middle gap-10 flex-1 overflow-hidden">
								<view>支付金额</view>
								<view>{{item.total_price}}</view>
							</view>
							<view class="acea-column column-middle gap-10 flex-1 overflow-hidden">
								<view>用户名</view>
								<view>{{ item.member.nickname }}</view>
							</view>
						</view>
						<view class="acea-row row-between-wrapper mt-20">
							<view>状态：{{item._status_text}}</view>
							<view>{{item.create_time}}</view>
						</view>
					</view>
				</view>
				<u-loadmore v-show="list.length" :status="loading" icon-type="circle"
					@loadmore="fetchData"></u-loadmore>
			</view>
		</scroll-view>
		<my-popup :show.sync="showFilter" title="筛选" :scrollHeight="1000">
			<result-filter :form-data="queryForm" @filter="doFilter" />
		</my-popup>
	</view>
</template>

<script>
	import _ from 'lodash'
	import MyPopup from '@/components/manage-search/my-popup'
	import Fiter from './components/filter'

	export default {
		components: {
			MyPopup,
			'result-filter': Fiter
		},
		data() {
			return {
				queryForm: {
					create_time: '',
					status: '',
					page: 1,
					limit: 10,
				},
				list: [],
				total: 0,
				loading: 'loadmore',
				showFilter: false,
			}
		},
		computed: {

		},
		watch: {

		},
		onReady() {

		},
		onLoad() {
			this.fetchData()
		},
		methods: {
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
				} = await this.$u.api.getRechargeReviewList(this.queryForm)
				this.total = total
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				return this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
			// 筛选回调
			doFilter(e) {
				this.showFilter = false
				_.merge(this.queryForm, e)
				this.reloadData()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.page {
		.scroll_content {
			height: calc(var(--vh) * 100 - 44px - var(--status-bar-height));
		}
	}

	.border-bottom {
		border-bottom: 1px solid #e5e5e5;
	}

	.filter-btn {
		cursor: pointer;
		border-radius: 5px;
		line-height: 1;
		display: flex;
		align-items: center;
		gap: 6rpx;
		margin-right: 20rpx;
		user-select: none;
	}

	.list-box {
		.list-wrap {
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			padding: 20rpx;

			.list-item {
				background-color: #fff;
				border-radius: 10rpx;
				padding: 30rpx;
			}
		}
	}
</style>