<template>
	<view class="button-box">
		<view class="button-list">
			<view class="button-item" :style="[itemStyle]" :class="{on:currIndex == index}" v-for="(item,index) in list"
				:key="index" @click="itemChange(item,index)" size="mini">{{item.label}}</view>
		</view>
	</view>
</template>

<script>
	import _ from 'lodash'
	export default {
		components: {

		},
		props: {
			source: {
				type: Array,
				default: () => []
			},
			// 每个按钮的宽度,百分比|[xxxx]rpx
			itemWidth: {
				type: [String, Number],
				default: '50%'
			},
			// 是否显示全部
			showAll: {
				type: Boolean,
				default: true,
			},
			value: {
				type: [Number, String],
				default: 0
			},
		},
		data() {
			return {
				currIndex: 0,
			}
		},
		computed: {
			itemStyle() {
				const re = {}
				if (_.isNumber(this.itemWidth))
					re.width = `${this.itemWidth}rpx`
				else
					re.width = `calc(${this.itemWidth} - 20rpx)`

				return re
			},
			list() {
				let re = []
				if (this.showAll) {
					re = [{
						label: '全部',
						value: ''
					}, ...this.source]
				} else {
					re = [...this.source]
				}

				return re
			},
		},
		watch: {
			value: {
				handler(nv) {
					this.currIndex = this.list.findIndex(item => item.value == nv)
				},
				immediate: true
			}
		},
		mounted() {

		},
		methods: {
			itemChange(item, index) {
				if (this.currIndex == index)
					return

				this.currIndex = index
				this.$emit('input', item.value)
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.button-box {
		width: 100%;

		.button-list {
			display: flex;
			justify-content: flex-start;
			flex-wrap: wrap;
			gap: 20rpx;

			.button-item {
				color: #606266;
				background-color: #ffffff;
				display: flex;
				align-items: center;
				justify-content: center;
				cursor: pointer;
				padding: 0 10rpx;
				transition: all 0.15s;
				border: 1px solid #c0c4cc;
				border-radius: 10rpx;
				height: 56rpx;
			}

			.on {
				color: #fff;
				background-color: #2979ff;
				border-color: #2979ff;
			}
		}
	}
</style>